import{_ as a,o,c as t,ae as e}from"./chunks/framework.BRIUyvy5.js";const c=JSON.parse('{"title":"股癌 每週摘要","description":"","frontmatter":{},"headers":[],"relativePath":"reports/guai/2026-W13.md","filePath":"reports/guai/2026-W13.md"}'),n={name:"reports/guai/2026-W13.md"};function s(p,r,g,l,i,h){return o(),t("div",null,[...r[0]||(r[0]=[e('<h1 id="股癌-每週摘要" tabindex="-1">股癌 每週摘要 <a class="header-anchor" href="#股癌-每週摘要" aria-label="Permalink to &quot;股癌 每週摘要&quot;">​</a></h1><h2 id="_2026-03-28" tabindex="-1">2026-03-28 <a class="header-anchor" href="#_2026-03-28" aria-label="Permalink to &quot;2026-03-28&quot;">​</a></h2><h1 id="ep648-3月28日" tabindex="-1">EP648 / 3月28日 <a class="header-anchor" href="#ep648-3月28日" aria-label="Permalink to &quot;EP648 / 3月28日&quot;">​</a></h1><blockquote><p>週次檔案：2026-W13（請依我提供的週次） 日期：2026-03-28 標題：EP648 / 3月28日</p></blockquote><p>內容</p><h2 id="_1-市場概況" tabindex="-1">1. 市場概況 <a class="header-anchor" href="#_1-市場概況" aria-label="Permalink to &quot;1. 市場概況&quot;">​</a></h2><p><strong>指數點數與百分比的心理脫鉤：</strong> 納斯達克期貨近期重挫約 2.3%，台指期夜盤也跌了 2.66%，這預示著台股下週可能再次面臨千點級別的跌幅 。然而主委強調，隨著台股站上三萬點大關，過去視為天價的「千點」現在僅代表 3% 左右的波動，投資者應逐漸適應這種絕對數值的膨脹 。我們不應被過去一萬點時代的記憶錨定，而是要改看百分比，才能正確衡量目前的市場風險 。</p><p><strong>美股頻頻破底引發的操作調整：</strong> 納斯達克指數近期再次出現破底走勢，這讓主委在美股的現金水位持續拉高，並在反彈無力時選擇減碼 。目前的市場體感非常類似去年的「Liberation Day」或是三、四月的大回檔時期，盤勢呈現連續下殺且重心不斷下移 。雖然主委平時偏好「右側交易」，但在極端恐慌的長黑 K 出現時，他也會進場撿一些具備韌性的標的 。</p><p><strong>中東地緣政治的戰雲密佈：</strong> 地緣政治不確定性是目前市場最大的變數，大量美國部隊正朝中東集結，包含空降兵與登陸部隊 。市場擔憂這可能演變成一場全面戰爭，導致股價在初期出現劇烈下殺，即便後續可能反轉向上，但短期的衝擊不容小覷 。主委認為目前美股的形態非常險惡，投資者必須具備隨時應對大崩盤的心理準備 。</p><p><strong>台美股表現的分歧與聯動：</strong> 雖然美股表現疲軟且持續震盪向下，但台股在內資或特定資金支撐下，許多強勢股依然處於右上角 。主委坦言他在台股的水位打得相當高，甚至已面臨「沒錢加碼」的窘境，只能從美股回收資金 。儘管亞股短期強勁，但若美股出現全面破底或地緣政治事件升溫，台股恐難以單獨倖免 。</p><p><strong>融資水位的重新定價：</strong> 隨著指數基期墊高，傳統判斷融資過高的絕對億元數值（如 3000 億）已不再適用 。現在判斷融資壓力應觀察百分比以及連續下殺後的斷頭點位，這才是目前真實的籌碼定價點 。投資者應意識到市場結構已改變，過時的指標會導致錯誤的停損或進場判斷。</p><p><strong>左側與右側交易的動態平衡：</strong> 在美股持續弱勢的環境下，主委採取積極減碼弱勢股、保留強勢股的策略 。加碼通常發生在趨勢確認的右側，但在面對崩跌時，騰出流動性是為了在真正的低點出現時有錢「超底」 。這種策略能避免資金被卡死在持續破底的標的中，提升整體投資組合的存活率。</p><h2 id="_2-關注的股票" tabindex="-1">2. 關注的股票 <a class="header-anchor" href="#_2-關注的股票" aria-label="Permalink to &quot;2. 關注的股票&quot;">​</a></h2><p><strong>蘋果（Apple）的過路費策略：</strong> 蘋果計畫開放 Siri 接口供其他 AI 模型串接，這符合主委對蘋果作為「AI 時代中介費收費員」的邏輯預期 。透過將 AI 整合進中低價位的 iPhone 與 Mac，蘋果能迅速擴大用戶基數，並向模型開發商收取規費 。這種策略讓蘋果無需投入如其他巨頭般龐大的資本支出（CAPEX），反而使其在近期財報緊繃的環境中表現相對強勢 。</p><p><strong>馬威爾（Marvell, MVEL）的強勢表現：</strong> 在大多數科技股走勢疲軟、紛紛破底之際，Marvell 的技術現行長得相當不錯，是少數維持強勢的標的 。雖然主委過去幾次挑戰這檔股票都鎩羽而歸，但他目前仍將部分美股部位轉移至此類強勢股上 。這反映出在市場低迷時，資金會主動匯聚到具備實質動能或新題材支持的個股。</p><p><strong>玻璃基板（GCS/TGV）的新浪潮：</strong> 市場近期高度聚焦於玻璃基板技術，這被視為解決 AI 晶片大型化後有機載板翹曲問題的關鍵方案 。主委預期玻璃核心載板（GCS）或玻璃通孔（TGV）技術約在 2027 年中至 2028 年才會真正大量放量 。即便目前尚無實質數字支撐，但市場情緒已開始提早佈局，重演了當年光通訊（CPO）提早數年炒作的戲碼 。</p><p><strong>英特爾（Intel）在封裝技術的領先：</strong> 英特爾在玻璃基板與先進封裝技術（如 EMIB）上佈局已久，甚至可能在先進製程落後的情況下，透過封裝技術扳回一城 。目前觀察到 Google 的 TPU 晶片由於尺寸過大，無法使用傳統台積電解決方案，轉而採用英特爾的 EMIB 封裝 。英特爾近期在展示會上端出玻璃基板搭配 EMIB 的方案，顯示其在下一代 AI 晶片基建中具備強大的競爭力 。</p><p><strong>博通（Broadcom, BRC）的玻璃測試進展：</strong> 博通在新加坡與日本的合資產線正積極進行玻璃基板的相關測試，並有台系設備廠參與其中 。雖然目前的交換機晶片尚未採用，但預期在第八代 Tomahawk（TH8）產品中，極高機率會正式導入玻璃基板 。這標誌著通訊巨頭也認可玻璃技術在提升訊號連接效率上的優勢。</p><p><strong>台積電（TSM）的面板與玻璃佈局：</strong> 雖然台積電目前主要使用玻璃載具（Glass Carrier），尚未在量產中大規模轉向玻璃中介層，但相關開發工作仍在持續進行 。如果未來台積電也明確宣布大量採用玻璃基板，將會是該題材正式「定調」的關鍵時刻 。主委認為目前這仍是一個偏向「夢想」的題材，但技術線圖已先行反映市場的期待 。</p><h2 id="_3-其他財經消息及知識" tabindex="-1">3. 其他財經消息及知識 <a class="header-anchor" href="#_3-其他財經消息及知識" aria-label="Permalink to &quot;3. 其他財經消息及知識&quot;">​</a></h2><p><strong>Google KV Cache 壓縮技術的市場誤讀：</strong> 市場近期因 Google 提出新的緩存壓縮技術而大殺記憶體類股，主委認為這是典型的「市場耍白痴」 。雖然壓縮技術能提升效率，但這類軟體優化通常會激發更廣泛的應用，進而帶動更龐大的硬體需求，即所謂的「傑文斯悖論」 。這與過去擔憂 AI 會取代搜尋引擎或消滅軟體業的邏輯一樣，最後往往被證明是錯誤的過度反應 。</p><p><strong>AI 時代的記憶體需求本質：</strong> 記憶體需求主要受到推論應用中對大數據提取的頻率影響，目前的壓縮技術主要針對 HBM 或 DDR5 等高階產品 。即便是為了優化效率，數據依然需要存放在 HBM 或 CPU 的 DRAM 中，甚至會溢流到更深層的冷儲存設備 。主委認為記憶體標的漲多後容易因風吹草動被拉回，但從產業面來看，長期需求並未因此受損 。</p><p><strong>玻璃基板解決翹曲（Warpage）問題：</strong> 隨著 AI 晶片與 HBM 整合後的封裝尺寸越來越大，傳統有機基板在受熱時極易產生翹曲，影響良率與效能 。玻璃基板的高平整度與耐熱特性，能有效支撐 3.3 倍光照尺寸以上的大型晶片封裝 。這是半導體業從 TSV（矽通孔）走向 TGV（玻璃通孔）的必然技術路徑之一 。</p><p><strong>透過雷射改質與時刻製造 TGV：</strong> TGV 技術並非直接火燒玻璃，而是透過雷射改質改變玻璃局部區域的性質，再進行化學濕式刻蝕 。被改質區域的蝕刻速度遠高於其他區域，從而精準地創造出用於信號連接的大量微型穿孔 。這項工藝對精度要求極高，相關設備供應鏈是投資者應關注的核心 。</p><p><strong>資訊吸收的「二加一反思」：</strong> 主委認為現代人過度仰賴 AI 寫筆記或獲取二次資訊，這可能導致對真相的解讀出現偏差 。他建議涉及賺錢決策的關鍵資訊（如公司法說會），最好是自己親自去聽，因為口氣中的樂觀或悲觀是 AI 難以精準捕捉的 。保持獨立思考並親自研究一手資料，才能在資訊爆炸的時代建立核心競爭力。</p><p><strong>個人健康的遺傳與管理：</strong> 主委近期因檢測出高血壓（第一期）與特定的遺傳性高膽固醇（子彈蛋白 LP(a)）而開始積極治療 。他坦言年輕時對醫囑不屑一顧，但有了孩子後，為了能看著孩子長大，心態轉向「無我」並全力配合醫療調整 。這種從狂放不羈到極度自律的轉變，體現了家庭責任對人生優先權的重新排序 。</p><h2 id="_4-q-a" tabindex="-1">4. Q&amp;A <a class="header-anchor" href="#_4-q-a" aria-label="Permalink to &quot;4. Q&amp;A&quot;">​</a></h2><p><strong>職場戀情的流言蜚語：</strong> 針對同辦公室夫妻被同事八卦的問題，主委犀利指出，通常只有「有錢老公配漂亮老婆」這類優秀組合才會引發嫉妒與酸言酸語 。同事們之所以八卦，是因為這對夫妻具備被嫉妒的價值，雜魚通常不會有人理會 。建議對這類「酸葡萄」心理採取冷處理，因為這正代表了你的生活品質優於他人 。</p><p><strong>RO 仙境傳說的遊戲心得：</strong> 主委分享他在 RO 中課金買到全身神裝，但這反而讓他感覺遊戲體驗被「玩壞了」，失去了成長的樂趣 。他建議玩家只需購買核心裝備來提升便利性，其餘應親自體驗遊戲的進度 。這也反映在人生中，太快獲得一切有時會讓人感到空虛且失去前進的動力。</p><p><strong>去日本旅遊並非難事：</strong> 針對聽眾許願希望賺錢去日本，主委直言這只是因為「懶惰」，因為目前日本旅遊成本有時比台灣國旅還低 。透過紅眼航班與商務旅館，小資族也能輕鬆成行 。他建議人生願望應許得大一點，不要將低門檻的娛樂視為終極目標 。</p><p><strong>投資 NVIDIA 獲利的實力與運氣：</strong> 對於有人 All-in NVIDIA 並以此自豪，主委認為這類單一標的的長期持有往往包含巨大的運氣成分，類似簽樂透中獎 。真正的實力來自於反覆執行期望值為正的策略並取得績效 。他提醒聽眾不要盲目模仿那些「看破不說破」的運氣仔，應專注於建立可持續的投資邏輯 。</p><p>**為人父母對「愛」的重新定義：**主委感性分享，有了孩子後才真正理解什麼是「無條件的愛」，這與對伴侶的愛完全不同 。在生死交關的假設題中，父母會毫不猶豫地選擇犧牲自己保全孩子 。這種體悟讓許多單身者無法理解，但卻是支持許多父母在職場與市場拚搏的終極動力 。</p><p><strong>處理親友登出的人間清醒：</strong> 針對好友或父母離世的恐懼，主委認為應把握當下，多與父母創造有趣的回憶 。他最近積極與父母拜訪，送好酒好食讓他們能與山友分享，藉此降低未來可能的遺憾 。面對生命中不可避免的「跳 Game」，提前做好心理準備並珍惜現有的陪伴才是正解 。</p><p><strong>特斯拉（Tesla）財務上的雷贅：</strong> 主委認為馬斯克的 Terafab 計畫雖然有長期降低成本的夢想，但在短期財務上絕對是個沉重的負擔 。這類 IDM（垂直整合）策略在轉型期會重創毛利，讓股價陷入像當年 Meta 轉向元宇宙時的崩跌狀態 。除非馬斯克能再次創造如 AI 或 FSD 般的奇蹟，否則目前信徒們需面臨長時間的信仰考驗 。</p><p><strong>減重與健康管理的實驗：</strong> 為了降低血壓與內臟脂肪，主委開始嘗試使用減重針劑，即便這可能會暫時破壞他對美食的熱情 。他發現自己對藥物似乎有抗性，食慾依然強勁，只是飽足感維持得更久 。這類為了長期健康而做的「人體實驗」，是他目前為了能長久陪伴孩子所做的最重要投資 。</p>',35)])])}const _=a(n,[["render",s]]);export{c as __pageData,_ as default};
